const u = $input.item.json;
const p = {
  update_id: u.update_id,
  update_type: 'unknown',
  chat_id: null, from_id: null,
  text: null, callback_data: null, callback_query_id: null,
  has_photo: false, has_video: false, file_id: null,
};
if (u.message) {
  const m = u.message;
  p.update_type = 'message';
  p.chat_id   = m.chat && m.chat.id;
  p.from_id   = m.from && m.from.id;
  p.text      = m.text || null;
  if (m.photo && m.photo.length > 0) {
    p.has_photo = true;
    const lg = m.photo.reduce((a,b) => ((a.file_size||0) > (b.file_size||0) ? a : b));
    p.file_id = lg.file_id;
  } else if (m.video) {
    p.has_video = true;
    p.file_id = m.video.file_id;
  } else if (m.document) {
    const mime = m.document.mime_type || '';
    if (mime.startsWith('video/')) { p.has_video = true; p.file_id = m.document.file_id; }
  }
} else if (u.callback_query) {
  const cb = u.callback_query;
  p.update_type = 'callback_query';
  p.chat_id   = cb.message && cb.message.chat && cb.message.chat.id;
  p.from_id   = cb.from && cb.from.id;
  p.callback_data     = cb.data || null;
  p.callback_query_id = cb.id;
}
return [{ json: p }];

const update = $('Code: Parse Update').item.json;
const raw    = $input.item.json;

// Supabase returns array for row queries
const session     = Array.isArray(raw) ? (raw[0] || null) : (raw && raw.chat_id ? raw : null);
const state       = session && session.current_step ? session.current_step : 'IDLE';
const sessionData = session && session.draft  ? session.draft  : {};

const chat_id           = update.chat_id;
const telegram_user_id  = update.from_id;
const update_type       = update.update_type;
const text              = update.text || '';
const callback_data     = update.callback_data || '';
const callback_query_id = update.callback_query_id || '';
const has_photo         = update.has_photo || false;
const has_video         = update.has_video || false;
const file_id           = update.file_id || '';

function ynKb(prefix) {
  return { inline_keyboard: [[
    { text: 'Yes', callback_data: prefix + '_yes' },
    { text: 'No',  callback_data: prefix + '_no'  },
  ]] };
}

// ---------- Consent checklist helpers (v2) ----------
function buildConsentKeyboard(flags) {
  const items = [
    [['q1', 'Job Description'], ['q2', 'Salary']],
    [['q3', 'Overtime'],         ['q4', 'Food']],
    [['q5', 'Prayer Policy'],    ['q7', 'Penalty Policy']],
  ];
  const rows = items.map(function (row) {
    return row.map(function (pair) {
      const key = pair[0], label = pair[1];
      return {
        text: (flags && flags[key] ? '\u2705 ' : '\u2610 ') + label,
        callback_data: 'consent_toggle:' + key,
      };
    });
  });
  return { inline_keyboard: rows };
}

function allChecklistDone(flags) {
  if (!flags) return false;
  const keys = ['q1', 'q2', 'q3', 'q4', 'q5', 'q7'];
  for (let i = 0; i < keys.length; i++) {
    if (flags[keys[i]] !== true) return false;
  }
  return true;
}

let out = {
  action_type: 'message_only',
  chat_id, telegram_user_id, callback_query_id, state,
  session_data: sessionData,
  telegram_message: '',
  telegram_reply_markup: null,
  need_delete: false,
  candidate_id: sessionData.candidate_id || null,
  order_id: sessionData.order_id || null,
  file_id: null, file_type: null,
  new_state: null, new_data: null,
  consent_message_id: null,
};

// Global /cancel
if (text === '/cancel') {
  out.action_type     = 'delete_end';
  out.need_delete     = !!(sessionData.candidate_id);
  out.candidate_id    = sessionData.candidate_id || null;
  out.telegram_message = 'Cancelled.';

out.tg_body = JSON.stringify(Object.assign({chat_id:out.chat_id,text:out.telegram_message,parse_mode:'HTML'}, out.telegram_reply_markup ? {reply_markup:out.telegram_reply_markup} : {}));
return [{ json: out }];
}

// Global /reset (alias for /cancel, distinct message)
if (text === '/reset') {
  out.action_type     = 'delete_end';
  out.need_delete     = !!(sessionData.candidate_id);
  out.candidate_id    = sessionData.candidate_id || null;
  out.telegram_message = 'Session reset. Type /add to start over.';

out.tg_body = JSON.stringify(Object.assign({chat_id:out.chat_id,text:out.telegram_message,parse_mode:'HTML'}, out.telegram_reply_markup ? {reply_markup:out.telegram_reply_markup} : {}));
return [{ json: out }];
}

// Global /help — list available commands. Does NOT change state or clear session.
if (text === '/help') {
  out.action_type      = 'message_only';
  out.telegram_message = '📋 Available commands:\n\n/add — Start adding a new candidate\n/cancel — Cancel current action and clear session\n/reset — Same as /cancel\n/help — Show this menu';

out.tg_body = JSON.stringify(Object.assign({chat_id:out.chat_id,text:out.telegram_message,parse_mode:'HTML'}, out.telegram_reply_markup ? {reply_markup:out.telegram_reply_markup} : {}));
return [{ json: out }];
}

switch (state) {
  case 'IDLE':
    if (text === '/add') {
      out.action_type = 'list_orders';
    } else {
      out.telegram_message = 'Type /add to start adding a candidate.';
    }
    break;

  case 'WAITING_ORDER_SELECTION':
    if (update_type === 'callback_query' && callback_data.startsWith('order_')) {
      const order_id = callback_data.substring(6);
      out.action_type = 'session_and_message';
      out.order_id    = order_id;
      out.new_state   = 'WAITING_PASSPORT_UPLOAD';
      out.new_data    = Object.assign({}, sessionData, { order_id });
      out.telegram_message = "Please upload the candidate's passport photo.";
    } else {
      out.telegram_message = 'Please select an order from the list, or type /cancel to exit.';
    }
    break;

  case 'WAITING_PASSPORT_UPLOAD':
    if (has_photo) {
      out.action_type = 'passport';
      out.file_id     = file_id;
      out.file_type   = 'photo';
    } else {
      out.telegram_message = 'Please send a photo of the passport.';
    }
    break;

  case 'WAITING_PASSPORT_CONFIRM':
    if (update_type === 'callback_query') {
      if (callback_data === 'passport_confirm_yes') {
        // v2: enter consent checklist instead of Q1
        const flagsInit = { q1: false, q2: false, q3: false, q4: false, q5: false, q7: false };
        // Parse full_name from candidate_id (format: PPNO_CleanName) if not already present
        let fullName = sessionData.full_name || '';
        if (!fullName && sessionData.candidate_id) {
          const parts = String(sessionData.candidate_id).split('_');
          if (parts.length > 1) fullName = parts.slice(1).join(' ');
        }
        if (!fullName) fullName = '(unknown)';
        const jobType   = sessionData.job_type_en    || '';
        const companyEn = sessionData.company_name_en || '';
        const newData = Object.assign({}, sessionData, {
          consent_flags: flagsInit,
          full_name: fullName,
        });
        out.action_type           = 'send_checklist';
        out.new_state             = 'WAITING_CONSENT_CHECKLIST';
        out.new_data              = newData;
        out.telegram_message      = 'Candidate: ' + fullName + '\n' +
                                    'Order: ' + jobType + ' \u2013 ' + companyEn + '\n\n' +
                                    'Please confirm all items below:';
        out.telegram_reply_markup = buildConsentKeyboard(flagsInit);
      } else if (callback_data === 'passport_confirm_no') {
        // Orphan the old candidate, go back to re-upload
        out.action_type = 'session_and_message';
        out.new_state   = 'WAITING_PASSPORT_UPLOAD';
        out.new_data    = { order_id: sessionData.order_id };
        out.telegram_message = 'Please re-upload the passport photo.';
      }
    } else {
      out.telegram_message = 'Please use the Yes/No buttons to confirm the name.';
    }
    break;

  case 'WAITING_CONSENT_CHECKLIST': {
    // v2: single-screen checklist with toggle buttons
    const baseFlags = { q1: false, q2: false, q3: false, q4: false, q5: false, q7: false };
    const flags = (sessionData && sessionData.consent_flags && typeof sessionData.consent_flags === 'object')
      ? Object.assign({}, baseFlags, sessionData.consent_flags)
      : Object.assign({}, baseFlags);
    const msgId = (sessionData && sessionData.consent_message_id) ? sessionData.consent_message_id : null;

    if (update_type === 'callback_query' && callback_data && callback_data.indexOf('consent_toggle:') === 0) {
      const qKey = callback_data.substring('consent_toggle:'.length);
      const validKeys = ['q1', 'q2', 'q3', 'q4', 'q5', 'q7'];
      if (validKeys.indexOf(qKey) === -1) {
        out.action_type = 'message_only';
        out.telegram_message = 'Invalid toggle.';
        break;
      }
      flags[qKey] = !flags[qKey];
      const newData = Object.assign({}, sessionData, { consent_flags: flags });
      if (allChecklistDone(flags)) {
        // All 6 ✅ → advance to WAITING_HEIGHT
        out.action_type      = 'session_and_message';
        out.new_state        = 'WAITING_HEIGHT';
        out.new_data         = newData;
        out.telegram_message = 'All confirmed! Height (e.g. 5.5 for 5ft 5in):';
      } else {
        // Just edit reply markup, don't send a new message
        out.action_type           = 'consent_toggle';
        out.new_state             = 'WAITING_CONSENT_CHECKLIST';
        out.new_data              = newData;
        out.telegram_reply_markup = buildConsentKeyboard(flags);
        out.consent_message_id    = msgId;
      }
    } else {
      out.action_type      = 'message_only';
      out.telegram_message = 'Please use the buttons below to confirm each item.';
    }
    break;
  }

  case 'WAITING_HEIGHT': {
    const h = parseFloat(text);
    if (update_type === 'message' && !isNaN(h) && h > 0) {
      out.action_type = 'session_and_message';
      out.new_state   = 'WAITING_WEIGHT';
      out.new_data    = Object.assign({}, sessionData, { height_ft: h });
      out.telegram_message = 'Weight in kg (e.g. 55):';
    } else { out.telegram_message = 'Invalid input. Please enter a number for height (e.g. 5.5):'; }
    break;
  }

  case 'WAITING_WEIGHT': {
    const w = parseFloat(text);
    if (update_type === 'message' && !isNaN(w) && w > 0) {
      out.action_type = 'session_and_message';
      out.new_state   = 'WAITING_AVATAR_UPLOAD';
      out.new_data    = Object.assign({}, sessionData, { weight_kg: w });
      out.telegram_message = "Please upload the candidate's avatar photo.";
    } else { out.telegram_message = 'Invalid input. Please enter a number for weight (e.g. 55):'; }
    break;
  }

  case 'WAITING_AVATAR_UPLOAD':
    if (has_photo) {
      out.action_type = 'avatar';
      out.file_id     = file_id;
      out.file_type   = 'photo';
    } else { out.telegram_message = 'Please send a photo for the avatar.'; }
    break;

  case 'WAITING_VIDEO_UPLOAD':
    if (has_video) {
      out.action_type = 'finalize';
      out.file_id     = file_id;
      out.file_type   = 'video';
    } else { out.telegram_message = 'Please send a video file.'; }
    break;

  default:
    out.telegram_message = 'An error occurred. Type /cancel to restart.';
    break;
}

out.tg_body = JSON.stringify(Object.assign({chat_id:out.chat_id,text:out.telegram_message,parse_mode:'HTML'}, out.telegram_reply_markup ? {reply_markup:out.telegram_reply_markup} : {}));
return [{ json: out }];

const se = $('Code: State Engine').item.json;
const crypto = require('crypto');
const secret = $env.TELEGRAM_BRIDGE_SECRET;
const payload = { action: 'list_orders', telegram_user_id: se.telegram_user_id };
const timestamp = Math.floor(Date.now() / 1000).toString();
const rawBody = JSON.stringify(payload);
const sig = crypto.createHmac('sha256', secret).update(timestamp + '.' + rawBody, 'utf8').digest('hex');
return [{ json: { payload, rawBody, timestamp, signature: sig, chat_id: se.chat_id, callback_query_id: se.callback_query_id } }];

const resp = $input.item.json;
const se   = $('Code: State Engine').item.json;
let newState, newData, message, markup = null;

if (resp.error === 'AGENT_NOT_LINKED') {
  message  = 'Your Telegram account is not linked to any agent. Please contact admin.';
  newState = 'IDLE'; newData = {};
} else if (resp.orders) {
  const orders = resp.orders;
  if (orders.length === 0) {
    message = 'You have no active orders assigned.'; newState = 'IDLE'; newData = {};
  } else {
    const keyboard = orders.map(o => [{
      text: (o.job_type_en || 'Order') + ' — ' + (o.company_name_en || '') +
            ' (' + o.current_count + '/' + o.total_labor + ')',
      callback_data: 'order_' + o.order_id,
    }]);
    message  = 'Select an order:';
    newState = 'WAITING_ORDER_SELECTION';
    newData  = {};
    markup   = { inline_keyboard: keyboard };
  }
} else {
  message = 'An error occurred. Please try again or type /cancel.'; newState = 'IDLE'; newData = {};
}
const tg_body = JSON.stringify(Object.assign({chat_id:se.chat_id,text:message,parse_mode:'HTML'}, markup ? {reply_markup:markup} : {}));
return [{ json: {
  chat_id: se.chat_id, callback_query_id: se.callback_query_id,
  new_state: newState, new_data: newData,
  telegram_message: message, telegram_reply_markup: markup, tg_body,
} }];

const se  = $('Code: State Engine').item.json;
const bin = $input.item.binary;
const base64Image = bin && bin.data ? bin.data.data : '';
const crypto = require('crypto');
const secret = $env.TELEGRAM_BRIDGE_SECRET;
const payload = {
  action: 'create_passport',
  telegram_user_id: se.telegram_user_id,
  order_id: se.order_id || (se.session_data && se.session_data.order_id) || '',
  chat_id: se.chat_id,
  image_base64: base64Image,
  force_update: false,
};
const timestamp = Math.floor(Date.now() / 1000).toString();
const rawBody = JSON.stringify(payload);
const sig = crypto.createHmac('sha256', secret).update(timestamp + '.' + rawBody, 'utf8').digest('hex');
return [{ json: { payload, rawBody, timestamp, signature: sig, chat_id: se.chat_id, callback_query_id: se.callback_query_id } }];

const resp = $input.item.json;
const se   = $('Code: State Engine').item.json;
let newState, newData, message, markup = null;

if (resp.candidate_id && !resp.duplicate) {
  const candId = resp.candidate_id;
  newState = 'WAITING_PASSPORT_CONFIRM';
  newData  = Object.assign({}, se.session_data, {
    candidate_id: candId,
    order_id: se.order_id || (se.session_data && se.session_data.order_id),
  });
  if (resp.ocr_success) {
    const parts = candId.split('_');
    const cleanName = parts.slice(1).join(' ');
    message = 'Passport detected. Name: ' + cleanName + '\nIs this correct?';
  } else {
    message = 'Could not read passport clearly. Name will be entered manually later.\nContinue with this passport?';
  }
  markup = { inline_keyboard: [[
    { text: 'Yes', callback_data: 'passport_confirm_yes' },
    { text: 'No',  callback_data: 'passport_confirm_no'  },
  ]] };
} else if (resp.duplicate) {
  const ex = resp.existing || {};
  message  = 'This candidate already exists: ' + (ex.full_name || ex.id_ld || 'unknown') +
             '. Type /cancel or send a different passport.';
  newState = 'WAITING_PASSPORT_UPLOAD';
  newData  = se.session_data;
} else if (resp.error === 'AGENT_NOT_LINKED') {
  message = 'Your Telegram account is not linked to any agent. Please contact admin.';
  newState = 'IDLE'; newData = {};
} else if (resp.error === 'ORDER_NOT_ASSIGNED') {
  message = 'You are not assigned to this order.'; newState = 'IDLE'; newData = {};
} else {
  message = 'An error occurred. Please try again or type /cancel.';
  newState = se.state; newData = se.session_data;
}
const tg_body = JSON.stringify(Object.assign({chat_id:se.chat_id,text:message,parse_mode:'HTML'}, markup ? {reply_markup:markup} : {}));
return [{ json: {
  chat_id: se.chat_id, callback_query_id: se.callback_query_id,
  new_state: newState, new_data: newData,
  telegram_message: message, telegram_reply_markup: markup, tg_body,
} }];

const se = $('Code: State Engine').item.json;
const crypto = require('crypto');
const secret = $env.TELEGRAM_BRIDGE_SECRET;
const payload = {
  action: 'delete_candidate',
  telegram_user_id: se.telegram_user_id,
  candidate_id: se.candidate_id,
};
const timestamp = Math.floor(Date.now() / 1000).toString();
const rawBody = JSON.stringify(payload);
const sig = crypto.createHmac('sha256', secret).update(timestamp + '.' + rawBody, 'utf8').digest('hex');
return [{ json: { payload, rawBody, timestamp, signature: sig } }];

const resp = $input.item.json;
const se   = $('Code: State Engine').item.json;
const filePath  = resp.result && resp.result.file_path ? resp.result.file_path : '';
  // Normalize absolute path (LOCAL mode) to relative path
  const normFilePath = filePath && filePath.startsWith('/') ? filePath.split('/').slice(5).join('/') : filePath;
const avatarUrl = ('https://portal.veraglobal.vn/tg-media' ? 'https://portal.veraglobal.vn/tg-media' + '/' + normFilePath : 'https://api.telegram.org/file/bot' + '8213635094:AAEHCNvFG6KNYEhMv2mRjIZHD660mgPd1vM' + '/' + filePath);
const newData = Object.assign({}, se.session_data, { avatar_url: avatarUrl });
return [{ json: {
  chat_id: se.chat_id, callback_query_id: se.callback_query_id,
  new_state: 'WAITING_VIDEO_UPLOAD', new_data: newData,
  telegram_message: 'Please send the candidate\'s video.',
  telegram_reply_markup: null,
  tg_body: JSON.stringify({chat_id:se.chat_id,text:'Please send the candidate\'s video.',parse_mode:'HTML'}),
} }];

const fileResp = $input.item.json;
const se       = $('Code: State Engine').item.json;

// Early-return if Telegram getFile failed or file_path is empty (e.g. video > 20MB)
if (!fileResp || !fileResp.ok || !fileResp.result || !fileResp.result.file_path) {
  return [{ json: {
    error: true,
    error_type: 'video_unavailable',
    chat_id: se.chat_id,
  }}];
}

const sd       = se.session_data || {};
const filePath = fileResp.result.file_path;
  // Normalize absolute path (LOCAL mode) to relative path
  const normFilePath = filePath && filePath.startsWith('/') ? filePath.split('/').slice(5).join('/') : filePath;
const videoUrl = ('https://portal.veraglobal.vn/tg-media' ? 'https://portal.veraglobal.vn/tg-media' + '/' + normFilePath : 'https://api.telegram.org/file/bot' + '8213635094:AAEHCNvFG6KNYEhMv2mRjIZHD660mgPd1vM' + '/' + filePath);

const flags = (sd.consent_flags && typeof sd.consent_flags === 'object')
  ? sd.consent_flags
  : { q1:false, q2:false, q3:false, q4:false, q5:false, q7:false };

const candidateConfirmed = {
  q1_viewed_materials: !!flags.q1,
  q2_agrees_terms:     !!flags.q2,
  q3_agrees_overtime:  !!flags.q3,
  q4_accepts_food:     !!flags.q4,
  q5_agrees_prayer:    !!flags.q5,
  q6_has_questions:    false,
  q6_questions_text:   'None',
  q7_confirms_penalty: !!flags.q7,
};

const crypto = require('crypto');
const secret = $env.TELEGRAM_BRIDGE_SECRET;
const payload = {
  action: 'finalize',
  telegram_user_id: se.telegram_user_id,
  candidate_id: sd.candidate_id || '',
  height_ft:    sd.height_ft    || 0,
  weight_kg:    sd.weight_kg    || 0,
  avatar_url:   sd.avatar_url   || '',
  video_urls:   [videoUrl],
  candidate_confirmed: candidateConfirmed,
};
const timestamp = Math.floor(Date.now() / 1000).toString();
const rawBody = JSON.stringify(payload);
const sig = crypto.createHmac('sha256', secret).update(timestamp + '.' + rawBody, 'utf8').digest('hex');
return [{ json: { payload, rawBody, timestamp, signature: sig, chat_id: se.chat_id } }];

const resp  = $input.item.json;
const se    = $('Code: State Engine').item.json;
const appUrl = $env.APP_URL || '';
let message;
if (resp.web_url) {
  message = 'Candidate finalized! View at: ' + appUrl + resp.web_url;
} else if (resp.error) {
  message = 'Finalize error: ' + resp.error + '. Please contact admin.';
} else {
  message = 'Candidate finalized. Check the portal for details.';
}
return [{ json: { chat_id: se.chat_id, telegram_message: message,
  tg_body: JSON.stringify({chat_id:se.chat_id,text:message,parse_mode:'HTML'}) } }];
